// 英语格式到期时间
- (NSString *)formattedExpiryStringFromDateString:(NSString *)dateString {
    NSDateFormatter *dateFormatter = [[NSDateFormatter alloc] init];
    [dateFormatter setLocale:[NSLocale localeWithLocaleIdentifier:@"en_US_POSIX"]];
    [dateFormatter setDateFormat:@"yyyy-MM-dd"];

    NSDate *expiryDate = [dateFormatter dateFromString:dateString];

    if (expiryDate) {
        if ([[NSLocale preferredLanguages].firstObject hasPrefix:@"zh"]) {
            [dateFormatter setDateFormat:@"yyyy-MM-dd"];
        } else if([[NSLocale preferredLanguages].firstObject hasPrefix:@"en"]) {
            [dateFormatter setDateFormat:@"MMM d, yyyy"];
        }
        return [NSString stringWithFormat:NSLocalizedString(@"于%@到期", nil), [dateFormatter stringFromDate:expiryDate]];
    }
    return [NSString stringWithFormat:NSLocalizedString(@"于%@到期", nil), dateString];
}

- (void)refreshProductData {
    [self.productCollectionView reloadData];

    if (self.productCollectionView.products.count > 0) {
        // 取消之前的选择
        NSArray *selectedItems = [self.productCollectionView indexPathsForSelectedItems];
        [selectedItems enumerateObjectsUsingBlock:^(NSIndexPath *indexPath, NSUInteger idx, BOOL *stop) {
            [self.productCollectionView deselectItemAtIndexPath:indexPath animated:NO];
        }];
        // 默认选中第一个
        NSIndexPath *firstIndexPath = [NSIndexPath indexPathForItem:0 inSection:0];
        [self.productCollectionView selectItemAtIndexPath:firstIndexPath
                                                animated:NO
                                          scrollPosition:UICollectionViewScrollPositionNone];
        [self updatePurchaseView:self.products[0]];

        self.purchaseView.userInteractionEnabled = YES;
    } else {    // 当前展示货架无商品，禁止商品相关交互
        self.purchaseView.userInteractionEnabled = NO;
    }
}


