+ (BOOL)isAppleSubscription:(WBProductModel *)productModel {
    BOOL isApplePay = productModel.payMethod & WBPaymentMethodApplePay;
    BOOL isSubscription = productModel.payMethod & WBPaymentMethodSubscription;
    if (isApplePay && isSubscription) {
        return TRUE;    // 苹果支付连续订阅
