#import "WBPaymentMethodView.h"

@implementation WBPaymentMethodView

- (instancetype)initWithPaymentMethod:(WBPaymentMethod)method
                               image:(UIImage *)image
                                text:(NSString *)text
                          buttonImageNormal:(UIImage *)buttonImageNormal
                       buttonImageSelected:(UIImage *)buttonImageSelected
                              target:(id)target
                            selector:(SEL)selector {
    self = [super init];
    if (self) {
        self.icon = [[UIImageView alloc] initWithImage:image];
        self.label = [[UILabel alloc] init];
        self.button = [UIButton buttonWithType:UIButtonTypeCustom];

        self.icon.layer.cornerRadius = WBRpt(4);
        self.icon.layer.masksToBounds = YES;

        self.label.text = text;
        self.label.textAlignment = NSTextAlignmentLeft;
        self.label.font = WBPrimaryBoldFont(14);
        self.label.textColor = WBTextColor1;

        [self.button setBackgroundImage:buttonImageNormal forState:UIControlStateNormal];
        [self.button setBackgroundImage:buttonImageSelected forState:UIControlStateSelected];
        [self.button addTarget:target action:selector forControlEvents:UIControlEventTouchUpInside];

        [self addSubview:self.icon];
        [self addSubview:self.label];
        [self addSubview:self.button];

        [self setupConstraints];
    }
    return self;
}

- (void)setupConstraints {
    BOOL isRTL = [WBAppManager sharedManager].isRTL;

    [self.icon mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self);
        if (isRTL) {
            make.right.equalTo(self).offset(-16);
        } else {
            make.left.equalTo(self).offset(16);
        }
        make.height.width.mas_equalTo(32);
    }];

    [self.label mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.icon);
        if (isRTL) {
            make.right.equalTo(self.icon.mas_left).offset(-8);
        } else {
            make.left.equalTo(self.icon.mas_right).offset(8);
        }
        make.width.mas_equalTo(ZOOM(80));
        make.height.mas_equalTo(ZOOM(16));
    }];

    [self.button mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.icon);
        if (isRTL) {
            make.left.equalTo(self.mas_left).offset(ZOOM(16));
        } else {
            make.right.equalTo(self.mas_right).offset(-ZOOM(16));
        }
        make.height.width.mas_equalTo(25);
    }];
}

@end


