- (instancetype)initWithFrame:(CGRect)frame {
    if (self = [super initWithFrame:frame]) {
        [self setUpUI];
    }
    return self;
}

#pragma mark - set up

- (void)setUpUI {
    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    if (self.isFromAwardsPage) {
        [self.contentView addSubview:self.BackgroundView];
    }
    [self.contentView addSubview:self.iconImageView];
    [self.contentView addSubview:self.powerLabel];
    // [self.contentView addSubview:self.descLabel];
}

- (void)addAllConstraints {
    if (self.isFromAwardsPage) {
        [_BackgroundView mas_makeConstraints:^(MASConstraintMaker *make) {
            if ([WBAppManager sharedManager].isRTL) {
                make.right.equalTo(self.contentView.mas_right);
            } else {
                make.left.equalTo(self.contentView.mas_left);
            }
            make.top.equalTo(self.contentView.mas_top);
            make.width.mas_equalTo(ZOOM(72));
            make.height.mas_equalTo(ZOOM(67));
        }];
    }

    [_iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.contentView);
        if (self.isFromAwardsPage) {
            make.top.equalTo(self.contentView.mas_top).offset(ZOOM(10));
            make.width.height.mas_equalTo(ZOOM(24));
        } else {
            make.top.equalTo(self.contentView).offset(ZOOM(2));
            make.width.height.mas_equalTo(ZOOM(40));
        }
    }];

    [_powerLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(_iconImageView.mas_bottom).offset(ZOOM(8));    // 权益文字在图片的下方
        make.centerX.equalTo(self.contentView);
        make.width.mas_equalTo(ZOOM(83));
        if (self.isFromAwardsPage) {
            make.height.mas_equalTo(ZOOM(15));
        }
    }];

//    [_descLabel mas_makeConstraints:^(MASConstraintMaker *make) {
//        make.top.equalTo(self.powerLabel.mas_bottom).offset(ZOOM(2));
//        make.left.equalTo(self.powerLabel);
//    }];
}


#pragma mark - fromAwardsPage

- (void)setIsFromAwardsPage:(BOOL)isFromAwardsPage {
    _isFromAwardsPage = isFromAwardsPage;

    // 清除旧约束
    [self.contentView.subviews makeObjectsPerformSelector:@selector(removeFromSuperview)];
    [self removeAllConstraints];

    // 动态重建布局
    [self addAllSubviews];
    [self addAllConstraints];
    [self layoutIfNeeded];
}

- (void)removeAllConstraints {
    [self.iconImageView mas_remakeConstraints:^(MASConstraintMaker *make) {}];
    [self.powerLabel mas_remakeConstraints:^(MASConstraintMaker *make) {}];
    [self.BackgroundView mas_remakeConstraints:^(MASConstraintMaker *make) {}];
}


#pragma mark - 懒加载

- (UIImageView *)iconImageView {
    if (_iconImageView == nil) {
        _iconImageView = [[UIImageView alloc] init];
    }
    return _iconImageView;
}

- (UILabel *)powerLabel {
    if (_powerLabel == nil) {
        _powerLabel = [[UILabel alloc] init];
        _powerLabel.font = [UIFont systemFontOfSize:ZOOM(12) weight:UIFontWeightBold];
        if (self.isFromAwardsPage) {
            _powerLabel.textColor = WBColorHex(0xF9DCBE);
        } else {
            _powerLabel.textColor = GreenColor_g;
        }
        _powerLabel.textAlignment = NSTextAlignmentCenter;
        _powerLabel.numberOfLines = 0;
        _powerLabel.lineBreakMode = NSLineBreakByWordWrapping;
    }
    return _powerLabel;
}

- (UILabel *)descLabel {
    if (_descLabel == nil) {
        _descLabel = [[UILabel alloc] init];
        _descLabel.font = WBPrimaryBoldFont(10);
        _descLabel.textColor = WBColorHex(0xBFA286);
    }
    return _descLabel;
}

- (UIView *)BackgroundView {
    if (_BackgroundView == nil) {
        _BackgroundView = [[UIView alloc] init];
        _BackgroundView.layer.backgroundColor = [UIColor clearColor].CGColor;
    }
    return _BackgroundView;
}

@end

