// 英语格式到期时间
- (NSString *)formattedExpiryStringFromDateString:(NSString *)dateString {
    NSDateFormatter *dateFormatter = [[NSDateFormatter alloc] init];
    [dateFormatter setLocale:[NSLocale localeWithLocaleIdentifier:@"en_US_POSIX"]];
    [dateFormatter setDateFormat:@"yyyy-MM-dd"];

    NSDate *expiryDate = [dateFormatter dateFromString:dateString];
    if (expiryDate) {
        if ([[NSLocale preferredLanguages].firstObject hasPrefix:@"zh"]) {
            [dateFormatter setDateFormat:@"yyyy-MM-dd"];
        } else if([[NSLocale preferredLanguages].firstObject hasPrefix:@"en"]) {
            [dateFormatter setDateFormat:@"MMM d, yyyy"];
        }
        return [NSString stringWithFormat:NSLocalizedString(@"于%@到期", nil), [dateFormatter stringFromDate:expiryDate]];
    }
    return [NSString stringWithFormat:NSLocalizedString(@"于%@到期", nil), dateString];
}


